## 六、代码优化

### 6.1 循环优化

```typescript
// 使用for循环代替forEach（性能更好）
// 坏的写法
items.forEach((item, index) => {
    process(item);
});

// 好的写法
for (let i = 0, len = items.length; i < len; i++) {
    process(items[i]);
}

// 缓存长度
for (let i = 0; i < items.length; i++)  // 每次都计算长度
// 改为
let len = items.length;
for (let i = 0; i < len; i++)
```

### 6.2 避免过深的递归

```typescript
// 递归会占用大量栈空间
// 使用迭代代替递归

// 坏的写法
function fibonacci(n: number): number {
    if (n <= 1) return n;
    return fibonacci(n - 1) + fibonacci(n - 2);
}

// 好的写法
function fibonacci(n: number): number {
    if (n <= 1) return n;
    let a = 0, b = 1;
    for (let i = 2; i <= n; i++) {
        let temp = a + b;
        a = b;
        b = temp;
    }
    return b;
}
```

### 6.3 使用位运算

```typescript
// 位运算比算术运算快

// 判断奇偶
if (n & 1)  // 比 n % 2 快

// 乘除2的幂次
n << 1  // n * 2
n >> 1  // n / 2
n >>> 1 // 无符号右移

// 取整
~~n     // 比 Math.floor 快
```

