            type: 'message',
            username: this.username,
            content: content,
            timestamp: Date.now()
        });
    }

    send(data) {
        if (this.ws && this.ws.readyState === WebSocket.OPEN) {
            this.ws.send(JSON.stringify(data));
        }
    }

    onMessage(handler) {
        this.messageHandler = handler;
    }
}

