### 1.4 请求超时处理

```javascript
function fetchWithTimeout(url, options = {}, timeout = 5000) {
    const controller = new AbortController();
    const signal = controller.signal;

    const timeoutId = setTimeout(() => {
        controller.abort();
    }, timeout);

    return fetch(url, {
        ...options,
        signal
    })
    .finally(() => {
        clearTimeout(timeoutId);
    });
}

// 使用
